#include <stdio.h>
#include <string.h>

int isPalindrome(char *s) {
    int i = 0, j = strlen(s) - 1;
    while (i < j) {
        if (s[i] != s[j]) return 0;
        i++; j--;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[200005];
        scanf("%s", s);
        int n = strlen(s);
        int count = 0;
        for (int i = 0; i < n; i++) {
            char temp[200005];
            strcpy(temp, s + i);
            strcat(temp, s);
            temp[n] = '\0';
            temp[2 * n] = '\0';
            if (isPalindrome(temp)) count++;
        }
        printf("%d\n", count);
    }
    return 0;
}

code.C++:
#include <iostream>
#include <string>
using namespace std;

bool isPalindrome(string s) {
    int i = 0, j = s.size() - 1;
    while (i < j) {
        if (s[i] != s[j]) return false;
        i++; j--;
    }
    return true;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        string s;
        cin >> s;
        int n = s.size();
        int count = 0;
        for (int i = 0; i < n; i++) {
            string temp = s.substr(i) + s.substr(0, i);
            if (isPalindrome(temp)) count++;
        }
        cout << count << endl;
    }
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static boolean isPalindrome(String s) {
        int i = 0, j = s.length() - 1;
        while (i < j) {
            if (s.charAt(i) != s.charAt(j)) return false;
            i++; j--;
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int n = s.length();
            int count = 0;
            for (int i = 0; i < n; i++) {
                String temp = s.substring(i) + s.substring(0, i);
                if (isPalindrome(temp)) count++;
            }
            System.out.println(count);
        }
    }
}

